  ('judicial-d35ec6db-moex-00047', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '依實務見解，下列何種情況不成立刑法第321條加重竊盜罪？', '["甲以螺絲起子撬開鎖頭竊取機車", "20歲之甲、19歲之乙及12歲之丙一同竊取財物", "甲在公寓之樓梯間竊取腳踏車", "甲侵入旅館房間竊取旅客財物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00048', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲改造一艘廢棄遠洋漁船，與友人乙、丙，乘船至某海港，上岸持槍劫掠港口商家。關於甲之行為，下列 何者正確？', '["成立加重搶奪罪", "成立加重強盜罪", "成立海盜罪", "成立恐嚇取財罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00049', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '撘高鐵的A下車時，不慎將其皮夾放在座位上，後來為乘客甲拾取，甲未交給警察機關，反而將其內的新 臺幣3,000元花用殆盡，甲的行為如何處置？', '["甲僅屬於民法的不當得利，並無刑法問題", "甲乃意圖為自己不法所有侵占遺失物，應構成刑法第337條犯罪", "甲乃將業務上持有他人之物侵占，應構成刑法第336條第2項犯罪", "甲乃是將自己持有他人之物侵占，應構成刑法第335條犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00050', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '犯詐欺罪而有下列何者情形之一者，處1年以上7年以下有期徒刑，得併科100萬元以下罰金？', '["冒用私人機構名義犯之", "2人以上共同犯之", "以廣播電視、電子通訊、網際網路或其他媒體等傳播工具，對公眾散布而犯之", "以不正方法由收費設備取得他人之物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00051', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-f335c5ad', 'sub-judicial-d35ec6db-02', NULL, 'essay', '甲男、乙女經臺北地方法院判決離婚確定，並指定未成年子女丙子之權
利義務行使或負擔由與丙同住臺北市大同區之甲男任之，惟乙得於每個
月第 1個週日由其與丙於桃園會面 3 小時。嗣甲拒絕使乙、丙會面，乙
女向法院聲請執行與丙會面交往，試問：
應由何法院管轄？又如乙女向無管轄權之法院聲請執行時，法院應如
何處理？（20 分）
又如執行名義另記載於未成年子女年滿 12 歲以後，應尊重未成年子
女之主觀意願，以符合未成年子女之最佳利益等語。倘乙女向執行法
院聲請執行後，經執行處移送家事庭調查審認未成年子女確無意願與
債權人會面交往，執行法院得否駁回債權人之聲請？（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "aeba7c168ec1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0413", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00052', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-f335c5ad', 'sub-judicial-d35ec6db-02', NULL, 'essay', '債權人是否得以執行債務人之保險契約為標的聲請強制執行？亦即請
求執行法院扣押債務人對保險公司之保險契約相關權利，進而由執行法
院解約後，執行債務人對保險公司之解約金或保單價值準備金。如可為
執行標的時，相關理論依據為何？又關於執行此一標的時，應受相關限
制為何？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "aeba7c168ec1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0413", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00053', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-f335c5ad', 'sub-judicial-d35ec6db-02', NULL, 'essay', '債權人甲持票面金額 200 萬元之本票裁定聲請執行債務人乙之存款債
權。核發扣押命令扣得 200萬元之債權後，乙以清償消滅為由，對甲提
起債務人異議之訴，同時訴請確認本票之票款請求權不存在，並依強制
執行法第 18 條第 2 項規定經法院命供擔保後停止執行。嗣有債權人丙
持債權金額 200萬元之確定終局判決為執行名義，另聲請執行債務人乙
對第三人丁之工程款債權150萬元，試問：甲得否聲請參與分配該筆工
程款債權？反之，債權人丙如非聲請執行債務人乙對第三人丁之工程款
債權而主張聲請執行前開乙之存款債權，或主張參與分配時，有無不
同？（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "aeba7c168ec1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0413", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00054', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-2909f946', 'sub-judicial-d35ec6db-03', NULL, 'essay', '甲與乙為丙之繼承人，設籍於桃園市的丙死亡時，留有桃園市郵局帳戶
一筆（存款新臺幣 3,000萬元）與汽車一輛（價值新臺幣300萬元），另
有位於高雄市之土地一筆（價值新臺幣 5,000萬元）。甲欲先就該筆不動
產進行遺產分割，惟乙表示不同意，甲遂向高雄地方法院起訴，並主張
該不動產為民事訴訟法第 10 條所稱之專屬管轄事件。高雄地方法院受
理後，作成變賣該不動產並依應繼分比例分配價金之判決。試問：本案
判決是否有程序上之違誤？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "5af716a5f6fa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00055', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-2909f946', 'sub-judicial-d35ec6db-03', NULL, 'essay', '甲與乙因金錢借貸發生爭議，乙提起給付訴訟，第一審法院判決乙勝訴，
命甲應給付新臺幣 100萬元。該判決送達後，甲不服，於法定期間內向
原第一審法院提出上訴狀，但該上訴狀內容僅載明下列事項：當事人及
其法定代理人、第一審判決及對該判決上訴之陳述、對第一審判決不服
之範圍及應如何廢棄或變更之聲明。試問：第二審法院應如何進行後續
審理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "5af716a5f6fa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00056', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-2909f946', 'sub-judicial-d35ec6db-03', NULL, 'essay', '甲涉犯刑法第 336 條第 2項業務侵占罪嫌，經檢察官向管轄法院提起公
